         [HttpPost]    // POST method for the controller, e.g., api/WebHooksController in this case  
          public async Task<IActionResult> Post([FromBody] WebhookRequest request) {    
            if (request == null || string.IsNullOrEmpty(request?.Url))  return BadRequest("Invalid Request"); // Checking for valid input   
             try{     
                var response = await _httpClient.GetAsync(request.Url);   // Fetch content from user-provided URL using Http Client    
